[TOOL_CALL] write_file({"path":"src/components/Navbar.tsx","content":""use client";

import { useState, useEffect } from "react";

const navLinks = [
  { label: "Home", href: "#home" },
  { label: "About", href: "#about" },
  { label: "Menu", href: "#menu" },
  { label: "Gallery", href: "#gallery" },
  { label: "Reservations", href: "#reservations" },
  { label: "Contact", href: "#contact" },
];

export function Navbar() {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ${
        scrolled
          ? "bg-charcoal-900/95 backdrop-blur-md shadow-lg shadow-black/20"
          : "bg-transparent"
      }`}
    >
      <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
        <div className="flex h-20 items-center justify-between">
          {/* Logo */}
          <a href="#home" className="flex items-center gap-2">
            <div className="flex h-10 w-10 items-center justify-center rounded-full border-2 border-gold-400">
              <span className="font-serif text-lg font-bold text-gold-400">
                M
              </span>
            </div>
            <div className="flex flex-col">
              <span className="font-serif text-lg font-semibold tracking-wide text-gold-300">
                La Maison Dorée
              </span>
              <span className="text-[10px] uppercase tracking-[0.25em] text-charcoal-300">
                Fine Dining
              </span>
            </div>
          </a>

          {/* Desktop Navigation */}
          <div className="hidden items-center gap-8 md:flex">
            {navLinks.map((link) => (
              <a
                key={link.href}
                href={link.href}
                className="text-sm uppercase tracking-wider text-charcoal-200 transition-colors duration-300 hover:text-gold-400"
              >
                {link.label}
              </a>
            ))}
          </div>

          {/* Reserve Button (Desktop) */}
          <a
            href="#reservations"
            className="hidden rounded-sm border border-gold-400 px-6 py-2 text-sm uppercase tracking-wider text-gold-400 transition-all duration-300 hover:bg-gold-400 hover:text-charcoal-900 md:inline-block"
          >
            Reserve
          </a>

          {/* Mobile Menu Button */}
          <button
            onClick={() => setIsOpen(!isOpen)}
            className="flex flex-col gap-1.5 md:hidden"
            aria-label="Toggle menu"
          >
            <span
              className={`h-0.5 w-6 bg-gold-400 transition-all duration-300 ${
                isOpen ? "translate-y-2 rotate-45" : ""
              }`}
            />
            <span
              className={`h-0.5 w-6 bg-gold-400 transition-all duration-300 ${
                isOpen ? "opacity-0" : ""
              }`}
            />
            <span
              className={`h-0.5 w-6 bg-gold-400 transition-all duration-300 ${
                isOpen ? "-translate-y-2 -rotate-45" : ""
              }`}
            />
          </button>
        </div>
      </div>

      {/* Mobile Menu */}
      <div
        className={`overflow-hidden transition-all duration-500 md:hidden ${
          isOpen ? "max-h-96 opacity-100" : "max-h-0 opacity-0"
        }`}
      >
        <div className="bg-charcoal-900/98 backdrop-blur-md px-4 pb-6 pt-2">
          {navLinks.map((link) => (
            <a
              key={link.href}
              href={link.href}
              onClick={() => setIsOpen(false)}
              className="block py-3 text-sm uppercase tracking-wider text-charcoal-200 transition-colors duration-300 hover:text-gold-400"
            >
              {link.label}
            </a>
          ))}
          <a
            href="#reservations"
            onClick={() => setIsOpen(false)}
            className="mt-3 block rounded-sm border border-gold-400 px-6 py-2.5 text-center text-sm uppercase tracking-wider text-gold-400 transition-all duration-300 hover:bg-gold-400 hover:text-charcoal-900"
          >
            Reserve a Table
          </a>
        </div>
      </div>
    </nav>
  );
}
"})
